use notify::{self, WatchError};
use std::fs::{self, File};
use std::io::{self, Write};
use std::path::Path;
use std::time::Duration;
use tokio::fs;
use tokio::time::{sleep, sleep_until};

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Configuration
    let source_dir = "/path/to/source/directory";
    let backup_dir = "/path/to/backup/directory";
    let log_file = "/path/to/log.txt";
    let log_interval = Duration::from_secs(5);

    // Create log file
    let log_file = File::create(log_file)?;
    let mut log_writer = io::BufWriter::new(log_file);

    // Watch source directory
    let watcher = notify::watcher(source_dir, notify::WatchOptions::new())
        .map_err(|e| Box::new(e))?
        .filter_map(|event| match event {
            notify::Event::Modify(path) => Some((path, "modified")),
            notify::Event::Create(path) => Some((path, "created")),
            notify::Event::Remove(path) => Some((path, "removed")),
            _ => None,
        });

    // Synchronization loop
    let mut is_syncing = false;
    let mut sync_count = 0;

    // Log initial message
    log_writer.write_all(b"Started synchronization...\n")?;

    // Run in a loop
    while let Some((path, event_type)) = watcher.next().await {
        if is_syncing {
            // Wait for synchronization to complete
            sleep_until(std::time::Instant::now() + log_interval).await?;
            is_syncing = false;
            sync_count = 0;
        }

        // Check if this event is a sync event
        if event_type == "modified" || event_type == "created" {
            is_syncing = true;
            sync_count += 1;
            log_writer.write_all(format!("Sync event: {} at {}", path.display(), std::time::Instant::now()).as_bytes())?;
            // Perform synchronization
            sync(path, backup_dir, &log_writer).await?;
        }
    }

    // Log final message
    log_writer.write_all(b"Sync completed.\n")?;
    Ok(())
}

async fn sync(path: &str, backup_dir: &str, log_writer: &mut io::BufWriter<File>) -> Result<(), Box<dyn std::error::Error>> {
    let source_path = Path::new(path);
    let backup_path = Path::new(backup_dir).join(source_path);

    // Ensure backup directory exists
    fs::create_dir_all(backup_dir).await?;

    // Copy file
    let source_file = File::open(source_path)?;
    let mut backup_file = File::create(backup_path)?;
    std::io::copy(&mut source_file, &mut backup_file).await?;

    // Log success
    log_writer.write_all(format!("Synced {} to {}", source_path.display(), backup_path.display()).as_bytes())?;
    Ok(())
}
