use tokio::sync::mpsc;
use tokio::task::spawn;
use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize, Debug)]
struct Inventory {
    store: String,
    items: HashMap<String, i32>,
}

#[derive(Serialize, Deserialize, Debug)]
struct InventoryData {
    inventories: Vec<Inventory>,
}

#[tokio::main]
async fn main() -> io::Result<()> {
    // Load inventory data from JSON file
    let data = load_inventory_data()?;
    let inventories: Vec<Inventory> = data.inventories.into_iter().map(|item| Inventory { store: item.store, items: item.items }).collect();

    // Create a channel for user input
    let (sender, receiver) = mpsc::channel(10);

    // Spawn tasks for handling user inputs
    for _ in 0..3 {
        spawn(async move {
            let mut input = String::new();
            print!("Enter store name: ");
            io::stdin().read_line(&mut input).await.ok()?;
            let store = input.trim().to_string();

            print!("Enter item name: ");
            io::stdin().read_line(&mut input).await.ok()?;
            let item = input.trim().to_string();

            print!("Enter new quantity: ");
            io::stdin().read_line(&mut input).await.ok()?;
            let quantity: i32 = input.trim().parse().unwrap();

            // Update inventory
            let mut inventory = data.inventories.iter_mut().find(|inv| inv.store == store).unwrap();
            inventory.items.insert(item, quantity);

            // Send update to the receiver
            sender.send((store, item, quantity)).await.ok()?;
        });
    }

    // Update inventory data
    let mut data = InventoryData {
        inventories: inventories.into_iter().map(|inv| inv).collect(),
    };

    // Save updated inventory data to JSON file
    save_inventory_data(&data).await?;

    Ok(())
}

fn load_inventory_data() -> io::Result<InventoryData> {
    let file = File::open("inventory.json")?;
    let mut contents = String::new();
    io::read_to_string(file).unwrap_into(&mut contents);

    let data: InventoryData = serde_json::from_str(&contents)?;
    Ok(data)
}

async fn save_inventory_data(data: &InventoryData) -> io::Result<()> {
    let file = File::create("inventory.json")?;
    let mut writer = serde_json::to_writer(file, data)?;
    writer.flush().await?;
    Ok(())
}
