fn parse_log_line(line: &str) -> Option<(String, String, String)> {
    let fields: Vec<&str> = line.split_whitespace().collect();
    if fields.len() < 3 {
        return None;
    }
    let timestamp = fields[0].to_string();
    let ip = fields[1].to_string();
    let log_data = fields[2].to_string();
    Some((timestamp, ip, log_data))
}

fn main() {
    let mut log_metrics = HashMap::new();
    let mut threads = vec![];

    // Open log files for reading
    let log_files = vec![
        "server1.log",
        "server2.log",
        "server3.log",
        "server4.log",
        "server5.log",
        "server6.log",
        "server7.log",
        "server8.log",
        "server9.log",
        "server10.log",
    ];

    for file in log_files {
        let file = File::open(file)?;
        let reader = BufReader::new(file);
        let thread = thread::spawn(move || {
            for line in reader.lines() {
                let line = line.unwrap();
                if let Some((timestamp, ip, log_data)) = parse_log_line(&line) {
                    // Parse JSON log data
                    let parsed_data: serde_json::Value = serde_json::from_str(&log_data).unwrap();
                    let status_code = parsed_data["status_code"].as_u64().unwrap_or(0);
                    let response_time = parsed_data["response_time"].as_f64().unwrap_or(0.0);

                    // Update metrics
                    if let Some(count) = log_metrics.get_mut(&ip) {
                        *count += 1;
                    } else {
                        log_metrics.insert(ip, 1);
                    }

                    if let Some(response_time) = response_time {
                        if let Some(count) = log_metrics.get_mut(&ip) {
                            *count += 1;
                        } else {
                            log_metrics.insert(ip, 1);
                        }
                    }

                    if status_code != 0 {
                        if let Some(count) = log_metrics.get_mut(&ip) {
                            *count += 1;
                        } else {
                            log_metrics.insert(ip, 1);
                        }
                    }
                }
            }
        });
        threads.push(thread);
    }

    for thread in threads {
        thread.join().unwrap();
    }
}
