    private static final ObjectMapper objectMapper = new ObjectMapper();
    private static final ExecutorService executor = Executors.newCachedThreadPool();

    public static void main(String[] args) {
        try (ServerSocket serverSocket = new ServerSocket(8080)) {
            System.out.println("Server started on port 8080");
            while (true) {
                Socket socket = serverSocket.accept();
                executor.submit(() -> handleRequest(socket));
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static void handleRequest(Socket socket) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
        PrintWriter out = new PrintWriter(socket.getOutputStream(), true);

        String inputLine = in.readLine();
        if (inputLine == null) {
            out.println("Error: No input received");
            return;
        }

        String[] parts = inputLine.split("=");
        if (parts.length != 2) {
            out.println("Error: Invalid format");
            return;
        }

        String text = parts[1];
        String result = analyzeSentiment(text);
        out.println(result);
    }

    private static String analyzeSentiment(String text) {
        // Simulate sentiment analysis using a simple rule-based approach
        if (text.contains("good") || text.contains("great")) {
            return "positive";
        } else if (text.contains("bad") || text.contains("worst")) {
            return "negative";
        } else {
            return "neutral";
        }
    }
