#[derive(Debug)]
struct ChatMessage {
    sender: String,
    content: String,
    timestamp: String,
}

#[derive(Debug)]
struct ChatLog {
    messages: Vec<ChatMessage>,
}

impl ChatLog {
    fn new() -> Self {
        ChatLog { messages: Vec::new() }
    }

    fn save(&self) -> Result<(), std::io::Error> {
        let path = Path::new("chat.log");
        let file = File::create(path)?;
        let mut writer = BufWriter::new(file);
        for msg in &self.messages {
            writeln!(writer, "Sender: {}, Content: {}, Timestamp: {}", msg.sender, msg.content, msg.timestamp)?;
        }
        Ok(())
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let log = ChatLog::new();
    let log_path = Path::new("chat.log");

    // Create a file to store chat history
    if !log_path.exists() {
        let file = File::create(log_path)?;
        let mut writer = BufWriter::new(file);
        writeln!(writer, "Chat Log Initialized")?;
    }

    // Set up the WebSocket server
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    println!("WebSocket server started on 127.0.0.1:8080");

    while let Ok((stream, addr)) = listener.accept().await {
        spawn(async move {
            // Handle client connection
            let mut client = tokio::net::TcpStream::connect(addr).await?;
            let mut reader = std::io::BufReader::new(client.try_clone().unwrap());
            let mut writer = std::io::BufWriter::new(client.try_clone().unwrap());

            // Handle chat messages
            let mut messages = Vec::new();
            let mut log = ChatLog::new();

            while let Ok(msg) = reader.read_until(std::io::Cursor::new("\n")).await {
                let msg = String::from_utf8_lossy(&msg);
                if msg.trim() == "" {
                    continue;
                }
                let parts: Vec<&str> = msg.split_whitespace().collect();
                if parts.len() < 2 {
                    continue;
                }
                let sender = parts[0].to_string();
                let content = parts[1..].join(" ");
                let timestamp = chrono::Utc::now().to_rfc3339_opts(chrono::SecondsFormat::Secs, false).to_string();

                messages.push(ChatMessage {
                    sender,
                    content,
                    timestamp,
                });

                // Save to log
                log.messages.push(ChatMessage {
                    sender,
                    content,
                    timestamp,
                });

                // Write to client
                writer.write_all(format!("{}: {}\n", sender, content).as_bytes()).await?;
                writer.flush().await?;
            }

            // Save chat log to file
            log.save().unwrap();

            // Close connection
            client.close().await?;
        });
    }

    Ok(())
}
