import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;

public class DataRetentionService {

    private static final String DB_URL = "jdbc:mysql://localhost:3306/yourdb";
    private static final String DB_USER = "youruser";
    private static final String DB_PASSWORD = "yourpassword";

    private final Map<String, String> retentionRules = new HashMap<>();

    public void setRetentionRule(String tableName, String duration) {
        retentionRules.put(tableName, duration);
    }

    public void startService() {
        ExecutorService executor = Executors.newSingleThreadExecutor();
        Future<?> future = executor.submit(() -> {
            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD)) {
                String sql = "SELECT * FROM retention_rules WHERE table_name = ?";
                try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                    stmt.setString(1, "your_table");
                    ResultSet rs = stmt.executeQuery();
                    while (rs.next()) {
                        String tableName = rs.getString("table_name");
                        String duration = rs.getString("duration");
                        setRetentionRule(tableName, duration);
                    }
                }
            } catch (SQLException e) {
                e.printStackTrace();
            }
        });

        try {
            future.get();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public void purgeData() {
        String sql = "DELETE FROM your_table WHERE retention_duration < ?";
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD)) {
            try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                long currentTime = System.currentTimeMillis();
                long duration = retentionRules.get("your_table");
                stmt.setLong(1, currentTime - duration);
                stmt.executeUpdate();
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        DataRetentionService service = new DataRetentionService();
        service.setRetentionRule("your_table", "30 days");
        service.startService();
        service.purgeData();
    }
}

