import java.io.*;
import java.net.*;
import java.util.*;
import java.util.concurrent.*;
import javax.websocket.*;
import javax.websocket.server.*;

@ServerEndpoint("/websocket")
public class WebSocketServer {

    private final ExecutorService executorService = Executors.newCachedThreadPool();

    @OnOpen
    public void onOpen(Session session) {
        executorService.submit(() -> {
            try {
                session.getBasicRemote().sendText("Connected");
            } catch (IOException e) {
                e.printStackTrace();
            }
        });
    }

    @OnMessage
    public void onMessage(String message, Session session) {
        try {
            session.getBasicRemote().sendText("Received: " + message);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    @OnClose
    public void onClose(Session session) {
        System.out.println("Connection closed: " + session.getId());
    }

    @OnError
    public void onError(Session session, Throwable throwable) {
        throwable.printStackTrace();
    }

    public void start() {
        try (ServerSocket serverSocket = new ServerSocket(8080)) {
            System.out.println("WebSocket server started on port 8080");
            while (true) {
                Socket socket = serverSocket.accept();
                Session session = SessionFactory.createSession(socket);
                executorService.submit(() -> {
                    try {
                        handleSession(session);
                    } catch (IOException e) {
                        e.printStackTrace();
                    }
                });
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private void handleSession(Session session) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(session.getInputStream()));
            PrintWriter writer = new PrintWriter(session.getOutputStream(), true);

            String inputLine;
            while ((inputLine = reader.readLine()) != null) {
                if ("exit".equals(inputLine)) {
                    writer.println("exit");
                    break;
                }
                writer.println(inputLine);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        WebSocketServer server = new WebSocketServer();
        server.start();
    }
}

