public class StockMarketAnalyzer {

    private static final String API_URL = "https://api.example.com/stock-data";
    private static final String DB_URL = "jdbc:sqlite:stock_data.db";
    private static final String DB_USER = "user";
    private static final String DB_PASSWORD = "password";

    public static void main(String[] args) {
        try (CloseableHttpClient client = HttpClients.createDefault()) {
            HttpGet request = new HttpGet(API_URL);
            String response = client.execute(request, response -> {
                if (response.getStatusLine().getStatusCode() == HttpsURLConnection.HTTP_OK) {
                    return response;
                } else {
                    throw new RuntimeException("Failed to fetch data from API");
                }
            });

            String json = response.toString();
            JSONObject jsonObject = new JSONObject(json);
            JSONArray dataArray = jsonObject.getJSONArray("data");

            List<Double> prices = new ArrayList<>();
            for (int i = 0; i < dataArray.length(); i++) {
                JSONObject data = dataArray.getJSONObject(i);
                String priceStr = data.getString("price");
                double price = Double.parseDouble(priceStr);
                prices.add(price);
            }

            calculateAndStoreData(prices);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void calculateAndStoreData(List<Double> prices) {
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD)) {
