use std::collections::VecDeque;

#[derive(Debug)]
enum Error {
    CsvParseError,
    DataStreamEnd,
    Other,
}

impl Error for Error {}

fn main() -> Result<(), Error> {
    let mut reader = BufReader::new(std::io::stdin());
    let mut entries = VecDeque::new();

    loop {
        let line = match reader.read_line(&mut String::new()) {
            Ok(_) => {
                let line = String::new();
                line
            },
            Err(e) => {
                return Err(Error::DataStreamEnd);
            }
        };

        if line.is_empty() {
            continue;
        }

        let entry: Result<String, _> = line.parse();
        if let Ok(entry) = entry {
            entries.push_back(entry);
        }
    }

    let mut moving_avg = VecDeque::new();
    let mut current_sum = 0;

    for entry in entries {
        let value: f64 = entry.parse().unwrap();
        moving_avg.push_back(value);
        current_sum += value;

        if moving_avg.len() > 10 {
            current_sum -= moving_avg.pop_front().unwrap();
        }

        if moving_avg.len() == 10 {
            let avg = current_sum / 10.0;
            println!("{} {}", avg, entry);
        }
    }

    Ok(())
}
