import java.io.*;
import java.util.*;

public class CSVProcessor {
    private static final String INPUT_FILE = "input.csv";
    private static final String OUTPUT_FILE = "output.csv";
    private static final String CONFIG_FILE = "config.json";

    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Usage: java CSVProcessor <inputFile> <outputFile> <configFile>");
            return;
        }

        String input = args[0];
        String output = args[1];
        String config = args[2];

        try (BufferedReader reader = new BufferedReader(new FileReader(input))) {
            List<String> lines = new ArrayList<>();
            String line;
            while ((line = reader.readLine()) != null) {
                lines.add(line);
            }

            List<String> processedLines = processLines(lines, config);
            try (BufferedWriter writer = new BufferedWriter(new FileWriter(output))) {
                for (String line : processedLines) {
                    writer.write(line);
                    writer.newLine();
                }
            }
        } catch (IOException e) {
            System.err.println("Error processing CSV file: " + e.getMessage());
        }
    }

    private static List<String> processLines(List<String> lines, String config) {
        Map<String, String> columnOrder = new HashMap<>();
        Map<String, Set<String>> duplicates = new HashMap<>();

        // Read configuration file
        try (BufferedReader reader = new BufferedReader(new FileReader(config))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String[] parts = line.split(",");
                if (parts.length == 2) {
                    columnOrder.put(parts[0], parts[1]);
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading configuration file: " + e.getMessage());
            return lines;
        }

        // Process each line
        List<String> processedLines = new ArrayList<>();
        for (String line : lines) {
            String[] cells = line.split(",");
            List<String> processedCellList = new ArrayList<>(cells.length);
            Set<String> uniqueCells = new HashSet<>();

            for (int i = 0; i < cells.length; i++) {
                String cell = cells[i];
                if (uniqueCells.contains(cell)) {
                    continue;
                }
                uniqueCells.add(cell);
                processedCellList.add(cell);
            }

            // Re-order columns based on configuration
            List<String> reorderedCells = new ArrayList<>();
            for (String column : columnOrder.keySet()) {
                reorderedCells.add(processedCellList.get(columnOrder.get(column)));
            }

            String processedLine = String.join(",", reorderedCells);
            processedLines.add(processedLine);
        }

        return processedLines;
    }
}

