use std::fs::File;
use std::io::{BufReader, BufWriter};
use std::path::Path;
use std::sync::{Arc, Mutex};
use std::time::Duration;
use tokio::net::TcpListener;
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::sync::mpsc;
use tokio::task::spawn;

#[derive(Debug)]
struct FileHandler {
    file: File,
    reader: BufReader<File>,
    writer: BufWriter<File>,
}

impl FileHandler {
    fn new(path: &str) -> Result<Self, std::io::Error> {
        let file = File::open(path)?;
        let reader = BufReader::new(file);
        let writer = BufWriter::new(file);
        Ok(Self { file, reader, writer })
    }
}

#[tokio::main]
async fn main() {
    // Create a TCP listener
    let listener = TcpListener::bind("127.0.0.1:3000").await.unwrap();

    // Create a channel for handling requests
    let (tx, rx) = mpsc::channel(16);

    // Spawn a task for each incoming connection
    while let Some(conn) = listener.accept().await {
        let tx = Arc::new(Mutex::new(tx));
        let rx = Arc::new(Mutex::new(rx));
        spawn(async move {
            let mut handler = handle_connection(conn, tx, rx).await;
            handler.await;
        });
    }
}

async fn handle_connection(
    conn: tokio::net::TcpStream,
    tx: Arc<Mutex<mpsc::Sender<()>>>,
    rx: Arc<Mutex<mpsc::Receiver<()>>,
) -> Result<(), std::io::Error> {
    let mut reader = conn.try_into_async_read().await?;
    let mut writer = conn.try_into_async_write().await?;

    // Read the HTTP request
    let mut request = String::new();
    loop {
        match reader.read_line(&mut request).await {
            Ok(0) => break,
            Err(e) => {
                eprintln!("Error reading request: {}", e);
                break;
            }
            Ok(n) => {
                if n == request.len() {
                    break;
                }
            }
        }
    }

    // Parse the request
    let mut parts: Vec<&str> = request.split_whitespace().collect();
    if parts.len() < 2 {
        return Err(std::io::Error::new(std::io::ErrorKind::InvalidData, "Invalid HTTP request"));
    }

    let method = parts[0];
    let path = parts[1];
    let mut query = parts[2..].iter().collect::<Vec<&str>>();

    // Determine MIME type
    let mime_type = match path {
        "/" => "text/html",
        _ => {
            let file = Path::new(path).to_string_lossy();
            let ext = Path::new(&file).extension().unwrap_or(&"");
            match ext {
                "html" => "text/html",
                "css" => "text/css",
                "js" => "application/javascript",
                "png" => "image/png",
                "jpg" => "image/jpeg",
                "gif" => "image/gif",
                "svg" => "image/svg+xml",
                _ => "application/octet-stream",
            }
        }
    };

    // Serve the file
    let file_path = Path::new(path).to_path_buf();
    if file_path.exists() {
        let handler = FileHandler::new(file_path.as_os_str()).unwrap();
        let mut file = handler.file;
        let reader = handler.reader;
        let writer = handler.writer;

        // Write the HTTP response
        writer.write_all(b"HTTP/1.1 200 OK\r\nContent-Type: ").unwrap();
        writer.write_all(format!("{};\r\n", mime_type).as_bytes()).unwrap();
        writer.write_all(b"Content-Length: ").unwrap();
        let len = std::fs::file_size(&file_path).unwrap_or(0);
        writer.write_all(&(len as u64).to_string().as_bytes()).unwrap();
        writer.write_all(b"\r\n\r\n").unwrap();

        // Read and write the file
        while let Some(chunk) = reader.read_buf(&mut Vec::new()).await {
            if chunk.is_empty() {
                break;
            }
            writer.write_all(&chunk).await?;
        }
    } else {
        // Serve a 404 error
        writer.write_all(b"HTTP/1.1 404 Not Found\r\nContent-Type: text/plain\r\nContent-Length: 13\r\n\r\n404 Not Found").unwrap();
    }

    // Close the connection
    writer.flush().await?;
    reader.flush().await?;
    Ok(())
}
