            entry_lock.disk_usage = entry.disk_usage;
            writer.write_all(format!("{},{} ,{} ,{}", entry.timestamp, entry.cpu_usage, entry.memory_usage, entry.disk_usage).as_bytes()).unwrap();
            sleep(Duration::from_secs(60));
        }
    });

    // Run the interval
    interval.tick().await;
}
