import java.io.*;
import java.net.*;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.*;

public class ResourceMonitor {
    private static final String REMOTE_CONFIG_URL = "https://config.server.com/api/settings";
    private static final String ALERT_LOG_PATH = "alert.log";
    private static final int CPU_THRESHOLD = 80;
    private static final int MEM_THRESHOLD = 80;
    private static final int ALERT_INTERVAL = 60; // in seconds

    public static void main(String[] args) {
        try {
            // Initialize alert log
            File alertLog = new File(ALERT_LOG_PATH);
            if (!alertLog.exists()) {
                alertLog.createNewFile();
            }

            // Periodically check system resources
            Thread monitorThread = new Thread(() -> {
                while (true) {
                    checkSystemResources();
                    try {
                        Thread.sleep(ALERT_INTERVAL * 1000);
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        break;
                    }
                }
            });
            monitorThread.start();

            // Periodically sync with remote config server
            Thread syncThread = new Thread(() -> {
                while (true) {
                    try {
                        syncWithRemoteConfig();
                        try {
                            Thread.sleep(ALERT_INTERVAL * 1000);
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                            break;
                        }
                    } catch (IOException e) {
                        System.err.println("Failed to sync with remote config server: " + e.getMessage());
                    }
                }
            });
            syncThread.start();
        } catch (IOException e) {
            System.err.println("Error initializing resource monitor: " + e.getMessage());
        }
    }

    private static void checkSystemResources() {
        ProcessBuilder pb = new ProcessBuilder("top", "-b", "-n", "1");
        Process process = pb.start();
        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line = reader.readLine();
        if (line != null && line.contains("cpu")) {
            String[] parts = line.split("\\s+");
            int cpuUsage = Integer.parseInt(parts[1]);
            if (cpuUsage > CPU_THRESHOLD) {
                logAlert("CPU", "High", cpuUsage);
            }
        }

        // Check memory usage
        pb = new ProcessBuilder("free", "-m");
        process = pb.start();
        reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        line = reader.readLine();
        if (line != null && line.contains("Mem")) {
            String[] parts = line.split("\\s+");
            int memUsage = Integer.parseInt(parts[2]);
            if (memUsage > MEM_THRESHOLD) {
                logAlert("Memory", "High", memUsage);
            }
        }
    }

    private static void logAlert(String resource, String level, int usage) {
        try {
            File alertLog = new File(ALERT_LOG_PATH);
            BufferedWriter writer = new BufferedWriter(new FileWriter(alertLog, true));
            String timestamp = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss").format(LocalDateTime.now());
            writer.write(String.format("%s,%s,%s,%d\n", timestamp, resource, level, usage));
            writer.close();
        } catch (IOException e) {
            System.err.println("Error logging alert: " + e.getMessage());
        }
    }

    private static void syncWithRemoteConfig() {
        try {
            URL url = new URL(REMOTE_CONFIG_URL);
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("GET");
            int responseCode = connection.getResponseCode();
            if (responseCode == 200) {
                BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println("Received config line: " + line);
                }
                reader.close();
            } else {
                System.err.println("Failed to sync with remote config server: " + responseCode);
            }
        } catch (IOException e) {
            System.err.println("Error syncing with remote config server: " + e.getMessage());
        }
    }
