use notify::{self, DebouncedEvent, Config, Event, EventFilter, Filter, RecursiveMode};
use chrono::Utc;
use std::fs::File;
use std::io::Write;
use std::path::Path;

fn main() {
    // Set up logging
    let log_file = "system_logs.txt";
    let log_dir = Path::new(log_file).parent().unwrap_or_else(|| Path::new(""));

    // Create log file if it doesn't exist
    if !log_dir.exists() {
        std::fs::create_dir_all(log_dir).expect("Failed to create log directory");
    }

    let mut log_file = File::create(log_dir.join(log_file)).unwrap();
    let mut log_writer = std::io::BufWriter::new(log_file);

    // Set up notify configuration
    let config = Config::new()
        .debounced(true)
        .interval(1000)
        .recursive(RecursiveMode::Continue);

    // Set up event filter
    let filter = EventFilter::new()
        .file_type(Filter::Any)
        .file_name(Filter::Any);

    // Start monitoring
    let mut watcher = notify::watcher(log_file, config).unwrap();
    let mut event_handler = Box::new(move |event: Event, context: &notify::Context| {
        let timestamp = Utc::now().format("%Y-%m-%d %H:%M:%S");
        let log_entry = format!("{} - {} - {}", timestamp, event, context);

        // Write log entry
        log_writer.write_all(log_entry.as_bytes()).unwrap();
        log_writer.write_all(b"\n").unwrap();

        // Handle event
        match event {
            Event::Create(e) => {
                let file_path = e.file();
                println!("File created: {}", file_path);
            }
            Event::Modify(e) => {
                let file_path = e.file();
                println!("File modified: {}", file_path);
            }
            Event::Remove(e) => {
                let file_path = e.file();
                println!("File deleted: {}", file_path);
            }
            _ => {}
        }
    });

    // Debounced event handling
    let debounced_event = DebouncedEvent::new(event_handler, 1000);
    watcher.subscribe(debounced_event).unwrap();
}
