use std::net::TcpListener;
use std::sync::{Mutex, MutexGuard};
use std::thread;
use serde_json::json;
use serde_json::Value;
use std::collections::HashMap;

struct Server {
    kv: Mutex<HashMap<String, i32>>,
}

impl Server {
    fn new() -> Self {
        Server {
            kv: Mutex::new(HashMap::new()),
        }
    }

    fn handle_request(&self, request: &str) -> Result<String, String> {
        let json: Value = serde_json::from_str(request).map_err(|e| e.to_string())?;
        let key = json["key"].str().unwrap().to_string();
        let value: i32 = json["value"].i32().unwrap_or(0);

        let mut kv = self.kv.lock().unwrap();
        *kv.entry(key).or_insert(&value) = value;

        Ok("OK".to_string())
    }
}

fn main() {
    let server = Server::new();
    let listener = TcpListener::bind("0.0.0.0:3000").unwrap();

    println!("Server is running on port 3000");

    for conn in listener.incoming() {
        let kv = server.kv.clone();
        let handle = thread::spawn(move || {
            let mut buffer = String::new();
            let mut reader = std::io::BufReader::new(conn.unwrap().read_to_end(buffer.as_mut()));
            let mut json_str = String::new();

            while reader.read_line(&mut json_str).unwrap() > 0 {
                let result = server.handle_request(&json_str);
                if let Err(e) = result {
                    eprintln!("Error: {}", e);
                }
            }
        });

        handle.join().unwrap();
    }
}
