import java.util.concurrent.*;
import java.sql.*;

public class TransactionalAnalyticsEngine {

    private static final String DB_URL = "jdbc:sqlite:transactions.db";
    private static final String DB_TABLE = "transactions";

    public static void main(String[] args) {
        try {
            // Initialize SQLite database
            initDatabase();

            // Fetch data from JSON-based REST API
            String apiUrl = "https://api.example.com/transactions";
            String jsonData = fetchFromApi(apiUrl);

            // Parse JSON data
            List<Map<String, Object>> transactions = parseJson(jsonData);

            // Process transactions using CompletableFuture
            List<CompletableFuture<Void>> futures = new ArrayList<>();
            for (Map<String, Object> transaction : transactions) {
                CompletableFuture<Void> future = CompletableFuture.runAsync(() -> {
                    processTransaction(transaction);
                });
                futures.add(future);
            }

            // Wait for all futures to complete
            CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();

            // Store results in SQLite database
            storeResults(transactions);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void initDatabase() {
        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            String sql = "CREATE TABLE IF NOT EXISTS " + DB_TABLE + " (id INTEGER PRIMARY KEY, amount REAL, timestamp TEXT)";
            try (Statement stmt = conn.createStatement()) {
                stmt.execute(sql);
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    private static String fetchFromApi(String url) throws IOException {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .build();
        return client.send(request, HttpResponse.BodyHandlers.ofString()).body();
    }

    private static List<Map<String, Object>> parseJson(String json) {
        List<Map<String, Object>> transactions = new ArrayList<>();
        try {
            JSONObject obj = new JSONObject(json);
            JSONArray transactionsArray = obj.getJSONArray("transactions");
            for (int i = 0; i < transactionsArray.length(); i++) {
                JSONObject transaction = transactionsArray.getJSONObject(i);
                Map<String, Object> map = new HashMap<>();
                map.put("amount", transaction.getDouble("amount"));
                map.put("timestamp", transaction.getString("timestamp"));
                transactions.add(map);
            }
        } catch (JSONException e) {
            e.printStackTrace();
        }
        return transactions;
    }

    private static void processTransaction(Map<String, Object> transaction) {
        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            String sql = "INSERT INTO " + DB_TABLE + " (amount, timestamp) VALUES (?, ?)";
            try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                pstmt.setDouble(1, (Double) transaction.get("amount"));
                pstmt.setString(2, (String) transaction.get("timestamp"));
                pstmt.executeUpdate();
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    private static void storeResults(List<Map<String, Object>> transactions) {
        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            String sql = "INSERT INTO " + DB_TABLE + " (amount, timestamp) VALUES (?, ?)";
            try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                for (Map<String, Object> transaction : transactions) {
                    pstmt.setDouble(1, (Double) transaction.get("amount"));
                    pstmt.setString(2, (String) transaction.get("timestamp"));
                    pstmt.addBatch();
                }
                pstmt.executeBatch();
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

