import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.TimeUnit;
import java.util.HashMap;
import java.util.Map;
import java.time.Duration;

public class CurrencyConverter {
    private static final String API_URL = "https://api.exchangerate-api.com/v4/latest/USD";
    private static final Map<String, Double> cachedRates = new HashMap<>();

    public static void main(String[] args) {
        // Cache rate for 10 minutes
        cachedRates.put("USD", 1.0);
        // Example usage
        String amount = "100";
        String fromCurrency = "USD";
        String toCurrency = "EUR";
        double convertedAmount = convert(amount, fromCurrency, toCurrency);
        System.out.println("Converted amount: " + convertedAmount);
    }

    public static double convert(String amount, String fromCurrency, String toCurrency) {
        // Check if rate is cached
        if (cachedRates.containsKey(fromCurrency) && cachedRates.containsKey(toCurrency)) {
            return cachedRates.get(fromCurrency) * Double.parseDouble(amount);
        }

        // Fetch rates from API
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder(URI.create(API_URL))
                .header("Accept", "application/json")
                .build();

        try {
            HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() == 200) {
                Map<String, Object> ratesMap = response.body().getJSONObject("rates");
                double fromRate = ratesMap.get(fromCurrency) == null ? 0 : (double) ratesMap.get(fromCurrency);
                double toRate = ratesMap.get(toCurrency) == null ? 0 : (double) ratesMap.get(toCurrency);

                // Cache for 10 minutes
                cachedRates.put(fromCurrency, fromRate);
                cachedRates.put(toCurrency, toRate);

                return fromRate * Double.parseDouble(amount);
            } else {
                throw new RuntimeException("Failed to fetch exchange rates");
            }
        } catch (Exception e) {
            e.printStackTrace();
            return 0;
        }
    }
}

