    // Parse command line arguments
    let args: Vec<String> = std::env::args().collect();
    let input_files: Vec<String> = args.iter().take(1).cloned().collect();
    let output_file = args.iter().nth(2).cloned().unwrap_or_default();

    // Validate input files
    if input_files.is_empty() {
        eprintln!("Error: No input files provided.");
        return Err("No input files provided.".into());
    }

    // Check if output file exists and is writable
    let output_path = Path::new(&output_file);
    let mut output_file = TokioFile::create(output_path).await?;
    output_file.write_all(b"{").await?;

    // Read and merge JSON files
    let mut merged = json!({});

    for file in &input_files {
