import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class URLShortener {

    private final ConcurrentHashMap<String, String> shortUrls = new ConcurrentHashMap<>();
    private final AtomicInteger accessCount = new AtomicInteger(0);

    public static void main(String[] args) {
        new URLShortener().start();
    }

    public void start() {
        HttpClient client = HttpClient.newHttpClient();
        // Endpoint for creating short URLs
        HttpRequest createRequest = HttpRequest.newBuilder()
                .uri(URI.create("http://localhost:8080/create"))
                .header("Content-Type", "application/json")
                .method("POST", HttpResponse.BodyPublishers.ofString("{\"url\": \"https://example.com\"}"))
                .build();

        // Endpoint for getting short URL
        HttpRequest getRequest = HttpRequest.newBuilder()
                .uri(URI.create("http://localhost:8080/short"))
                .header("Content-Type", "application/json")
                .method("GET", HttpResponse.BodyPublishers.ofString("{\"short\": \"abc123\"}"))
                .build();

        // Endpoint for accessing short URL
        HttpRequest accessRequest = HttpRequest.newBuilder()
                .uri(URI.create("http://localhost:8080/access"))
                .header("Content-Type", "application/json")
                .method("GET", HttpResponse.BodyPublishers.ofString("{\"short\": \"abc123\"}"))
                .build();

        // Endpoint for tracking access
        HttpRequest accessCountRequest = HttpRequest.newBuilder()
                .uri(URI.create("http://localhost:8080/access-count"))
                .header("Content-Type", "application/json")
                .method("GET", HttpResponse.BodyPublishers.ofString("{\"short\": \"abc123\"}"))
                .build();

        // Register endpoints
        client.sendAsync(createRequest, HttpResponse.BodyPublishers.ofString("{}"), httpResponse -> {
            if (httpResponse.statusCode() == 200) {
                System.out.println("Short URL created");
            }
        });

        client.sendAsync(getRequest, httpResponse -> {
            if (httpResponse.statusCode() == 200) {
                System.out.println("Short URL retrieved");
            }
        });

        client.sendAsync(accessRequest, httpResponse -> {
            if (httpResponse.statusCode() == 200) {
                System.out.println("Access count updated");
            }
        });

        client.sendAsync(accessCountRequest, httpResponse -> {
            if (httpResponse.statusCode() == 200) {
                System.out.println("Access count retrieved");
            }
        });
    }
