public class ThreatScoreDaemon {
    private static final String LOG_FILE_PATH = "path/to/logfile.log";
    private static final String BLACKLIST_URL = "https://blacklist.example.com/api";

    private static final Map<String, Integer> ipToScore = new HashMap<>();

    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java ThreatScoreDaemon <logFilePath> <blacklistURL>");
            return;
        }

        String logFilePath = args[0];
        String blacklistURL = args[1];

        try {
            // Read log file
            BufferedReader reader = new BufferedReader(new FileReader(logFilePath));
            String line;
            int score = 0;

            while ((line = reader.readLine()) != null) {
                // Extract IP address from line
                String ip = extractIpAddress(line);
                if (ip != null) {
                    // Update score based on IP
                    score = updateScore(ip, blacklistURL);
                    ipToScore.put(ip, score);
                }
            }

            reader.close();
        } catch (IOException e) {
            e.printStackTrace();
        }

        // Print in-memory map
        System.out.println("In-memory IP threat scores:");
        for (Map.Entry<String, Integer> entry : ipToScore.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }

    private static String extractIpAddress(String line) {
        // Simple regex to extract IP address from line
        Pattern pattern = Pattern.compile("(\\d{1,3}\\.|\\d{1,3}\\.){3}\\d{1,3}");
        Matcher matcher = pattern.matcher(line);
        if (matcher.find()) {
            return matcher.group();
        }
        return null;
    }

    private static int updateScore(String ip, String blacklistURL) {
        // Fetch blacklist data
        try {
            HttpClient client = HttpClient.newHttpClient();
            HttpRequest request = HttpRequest.newBuilder(URI.create(blacklistURL))
                    .header("Accept", "application/json")
                    .build();

            HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() == 200) {
                // Parse JSON response
                JSONObject json = new JSONObject(response.body());
                JSONArray blacklistedIPs = json.getJSONArray("blacklisted_ips");

                // Check if IP is in blacklist
                for (int i = 0; i < blacklistedIPs.length(); i++) {
                    String blacklistedIp = blacklistedIPs.getString(i);
                    if (blacklistedIp.equals(ip)) {
                        return 100; // High threat score
                    }
                }
            }
        } catch (IOException | JSONException e) {
            e.printStackTrace();
        }

        // Default score
        return 50;
    }
}

