    // JDBC repository
    static class JdbcRepository implements Repository<Book> {
        private final DataSource dataSource;

        JdbcRepository(DataSource dataSource) {
            this.dataSource = dataSource;
        }

        @Override
        public void save(Book entity) {
            String sql = "INSERT INTO books (title, author, year) VALUES (?, ?, ?)";
            try (PreparedStatement stmt = dataSource.getConnection().prepareStatement(sql)) {
                stmt.setString(1, entity.title());
                stmt.setString(2, entity.author());
                stmt.setInt(3, entity.year());
                stmt.executeUpdate();
            } catch (SQLException e) {
                throw new RuntimeException("Failed to save book", e);
            }
        }

        @Override
        public Book findById(Long id) {
            String sql = "SELECT * FROM books WHERE id = ?";
            try (PreparedStatement stmt = dataSource.getConnection().prepareStatement(sql)) {
                stmt.setLong(1, id);
                try (ResultSet rs = stmt.executeQuery()) {
                    if (rs.next()) {
                        return new Book(rs.getString(1), rs.getString(2), rs.getInt(3));
                    }
                }
            } catch (SQLException e) {
                throw new RuntimeException("Failed to find book", e);
            }
            return null;
        }

        @Override
        public void deleteById(Long id) {
            String sql = "DELETE FROM books WHERE id = ?";
            try (PreparedStatement stmt = dataSource.getConnection().prepareStatement(sql)) {
                stmt.setLong(1, id);
                stmt.executeUpdate();
            } catch (SQLException e) {
                throw new RuntimeException("Failed to delete book", e);
            }
        }

        @Override
        public Iterable<Book> findAll() {
            String sql = "SELECT * FROM books";
            try (PreparedStatement stmt = dataSource.getConnection().prepareStatement(sql)) {
                try (ResultSet rs = stmt.executeQuery()) {
                    Iterable<Book> result = rs.stream()
                            .map(row -> new Book(row.getString(1), row.getString(2), row.getInt(3)))
                            .collect(java.util.stream.Collectors.toList());
                    return result;
                }
            } catch (SQLException e) {
                throw new RuntimeException("Failed to find books", e);
            }
        }
    }

    // Service class
    static class CatalogService {
        private final Repository<Book> repo;

        CatalogService(Repository<Book> repo) {
            this.repo = repo;
        }

        public Book create(Book book) {
            repo.save(book);
            return book;
        }

        public Book read(Long id) {
            return repo.findById(id);
        }

        public Book update(Book book) {
            repo.save(book);
            return book;
        }

        public void delete(Long id) {
            repo.deleteById(id);
        }
    }

    // Async handling using CompletableFuture and virtual threads
    static class AsyncCatalogService extends CatalogService {
        private final ExecutorService executor = Executors.newVirtualThreadExecutor();

        AsyncCatalogService(Repository<Book> repo) {
            super(repo);
        }

        @Override
        public Book create(Book book) {
            executor.submit(() -> {
                super.create(book);
            });
            return book;
        }

        @Override
        public Book read(Long id) {
            executor.submit(() -> {
                super.read(id);
            });
            return super.read(id);
        }

        @Override
        public Book update(Book book) {
            executor.submit(() -> {
                super.update(book);
            });
            return super.update(book);
        }

        @Override
        public void delete(Long id) {
            executor.submit(() -> {
                super.delete(id);
            });
        }
    }

    // RESTful endpoints using HTTP Client (JDK 17)
    static class HttpCatalogService {
