use std::fs::File;
use std::io::{BufWriter, Write};
use std::path::Path;
use std::time::SystemTime;
use sha2::Sha256;
use tokio::fs::File as TokioFile;
use tokio::io::{AsyncWriteExt, BufReader};
use tokio::sync::mpsc;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Define the directory to monitor
    let monitor_dir = "/path/to/monitor/directory";
    let log_file = "/path/to/log/file.log";

    // Create a channel for communication
    let (sender, receiver) = mpsc::channel(100);

    // Spawn a task to monitor the directory
    let handle = tokio::spawn(async move {
        loop {
            // Check for new or modified files
            let files = find_files(monitor_dir).await?;
            for file in files {
                let file_path = file.path;
                let file_name = file.name.clone();

                // Get modification time
                let modification_time = SystemTime::now()
                    .duration_since(SystemTime::UNIX_EPOCH)
                    .unwrap()
                    .as_secs();

                // Compute SHA-256 hash
                let hash = compute_sha256(file_path).await?;

                // Log the event
                let log_entry = format!(
                    "[{}] - {} - {} - {}",
                    modification_time,
                    file_name,
                    hash,
                    file_path
                );
                sender.send(log_entry).await.unwrap();
            }

            // Sleep for a while before checking again
            std::thread::sleep(std::time::Duration::from_secs(5));
        }
    });

    // Spawn a task to handle logging
    let handle = tokio::spawn(async move {
        let mut log_file = BufWriter::new(File::create(log_file).await.unwrap());
        loop {
            let log_entry = receiver.recv().await.unwrap();
            log_file.write_all(log_entry.as_bytes()).await.unwrap();
            log_file.flush().await.unwrap();
        }
    });

    // Wait for both tasks to complete
    handle.await.unwrap();
    handle.await.unwrap();
    Ok(())
}

fn find_files(directory: &str) -> Result<Vec<FileEntry>, Box<dyn std::error::Error>> {
    let mut files = Vec::new();
    let path = Path::new(directory);

    if !path.exists() {
        return Err("Directory does not exist".into());
    }

    if let Ok(entries) = std::fs::read_dir(path) {
        for entry in entries {
            let entry = entry?;
            let path = entry.path();
            if path.is_file() {
                files.push(FileEntry {
                    path,
                    name: path.file_name().unwrap().to_str().unwrap().to_string(),
                });
            }
        }
    }

    Ok(files)
}

struct FileEntry {
    path: String,
    name: String,
}

fn compute_sha256(file_path: &str) -> Result<String, Box<dyn std::error::Error>> {
    let file = std::fs::File::open(file_path)?;
    let mut hasher = Sha256::new();
    let mut reader = BufReader::new(file);

    let mut contents = String::new();
    std::io::read_to_string(&mut contents, &mut reader).unwrap();

    hasher.update(contents.as_bytes());
    let hash = hasher.finalize();

    Ok(format!("{:x}", hash))
}
