public class WeatherApp {
    private static final String API_KEY = "YOUR_API_KEY_HERE";
    private static final String API_URL = "https://api.weatherapi.com/v1/current.json?key=" + API_KEY;

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String city = "";

        while (true) {
            System.out.print("Enter city name (or type 'exit' to quit): ");
            city = scanner.nextLine().trim();

            if (city.equalsIgnoreCase("exit")) {
                break;
            }

            try {
                String response = fetchWeatherData(city);
                if (response != null) {
                    parseAndDisplayWeather(response);
                } else {
                    System.out.println("Failed to retrieve weather data.");
                }
            } catch (IOException | JSONException e) {
                System.out.println("Error: " + e.getMessage());
            }
        }

        scanner.close();
    }

    private static String fetchWeatherData(String city) throws IOException {
        URL url = new URL(API_URL + "&q=" + city);
        HttpURLConnection connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("GET");

        int responseCode = connection.getResponseCode();
        if (responseCode == 200) {
            BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
            String line;
            StringBuilder response = new StringBuilder();
            while ((line = reader.readLine()) != null) {
                response.append(line);
            }
            reader.close();
            return response.toString();
        } else {
            return null;
        }
    }

    private static void parseAndDisplayWeather(String json) throws JSONException {
        JSONObject weatherData = new JSONObject(json);
        JSONObject current = weatherData.getJSONObject("current");

        JSONObject location = weatherData.getJSONObject("location");
        String cityName = location.getString("name");

        JSONObject weather = current.getJSONObject("weather");
        String temperature = weather.getString("temp_c") + "°C";
        String windSpeed = weather.getString("wind_kph") + " km/h";
        String precipitation = weather.getString("precipitation") + " mm";

        System.out.println("City: " + cityName);
        System.out.println("Temperature: " + temperature);
        System.out.println("Wind Speed: " + windSpeed);
        System.out.println("Precipitation: " + precipitation);
        System.out.println("----------------------------------------");
    }
}

