public class ConfigFileMonitor {
    private static final String LOG_FILE = "config_changes.log";
    private static final String WATCH_DIR = "config_files";

    public static void main(String[] args) {
        try {
            // Create the watch directory if it doesn't exist
            Files.createDirectories(Paths.get(WATCH_DIR));

            // Initialize the WatchService
            WatchService watchService = FileSystems.getDefault().newWatchService();

            // Register the watch directory
            Path dir = Paths.get(WATCH_DIR);
            dir.register(watchService);

            // Log the start of the monitoring
            logEvent("Monitoring started for directory: " + WATCH_DIR);

            // Watch for changes
            while (true) {
                WatchEvent<?> event = watchService.poll(1000, TimeUnit.MILLISECONDS);
                if (event == null) {
                    break;
                }

                // Process the event
                processEvent(event);
            }

            // Log the end of the monitoring
            logEvent("Monitoring stopped.");

        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    private static void processEvent(WatchEvent<?> event) {
        Path filePath = null;
        EventType eventType = null;

        // Determine the type of event
        if (event.getType() == WatchEvent.Type.ENTRY_CHANGED) {
            eventType = EventType.CHANGED;
        } else if (event.getType() == WatchEvent.Type.ENTRY_DELETED) {
            eventType = EventType.DELETED;
        } else if (event.getType() == WatchEvent.Type.ENTRY_CREATED) {
            eventType = EventType.CREATED;
        }

        // Determine the file path
        if (event.getType() == WatchEvent.Type.ENTRY_CHANGED || event.getType() == WatchEvent.Type.ENTRY_DELETED || event.getType() == WatchEvent.Type.ENTRY_CREATED) {
            filePath = event.context().getPath();
        }

        // Log the event
        logEvent(eventType, filePath, Instant.now());
    }

    private static void logEvent(EventType type, Path file, Instant timestamp) {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(LOG_FILE, true))) {
            writer.write(String.format("%s %s %s %s\n", 
                type.name(), 
                file.getFileName().toString(), 
                timestamp.toString(), 
                file.toAbsolutePath().toString()));
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    // Enum for event types
    enum EventType {
        CHANGED, DELETED, CREATED
    }
}

import java.io.*;
import java.net.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.logging.Logger;

public class HealthMonitor {
    private static final Logger logger = Logger.getLogger(HealthMonitor.class.getName());
    private static final String CONFIG_FILE = "health-monitor-config.properties";
    private static final int DEFAULT_INTERVAL = 5;
    private static final int MAX_ATTEMPTS = 3;
    private static final int ERROR_THRESHOLD = 3;

    private final String[] urls;
    private final int interval;
    private final int maxAttempts;
    private final int errorThreshold;

    public HealthMonitor(String[] urls, int interval, int maxAttempts, int errorThreshold) {
        this.urls = urls;
        this.interval = interval;
        this.maxAttempts = maxAttempts;
        this.errorThreshold = errorThreshold;
    }

    public void startMonitoring() {
        ExecutorService executor = Executors.newFixedThreadPool(urls.length);
        List<CompletableFuture<Void>> futures = new ArrayList<>();

        for (int i = 0; i < urls.length; i++) {
            CompletableFuture<Void> future = CompletableFuture.runAsync(() -> {
                try {
                    if (checkServer(urls[i])) {
                        logger.info("Server " + urls[i] + " is up and responding.");
                    } else {
                        logger.warning("Server " + urls[i] + " is down or returns an error.");
                    }
                } catch (IOException e) {
                    logger.severe("Error checking server " + urls[i] + ": " + e.getMessage());
                }
            }, executor);

            futures.add(future);
        }

        try {
            CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();
        } catch (Exception e) {
            logger.severe("Error in monitoring: " + e.getMessage());
        } finally {
            executor.shutdown();
        }
    }

    private boolean checkServer(String url) throws IOException {
        int attempts = 0;
        while (attempts < maxAttempts) {
            try {
                URL urlObj = new URL(url);
                HttpURLConnection connection = (HttpURLConnection) urlObj.openConnection();
                connection.setRequestMethod("GET");
                connection.setConnectTimeout(10000);
                connection.setReadTimeout(10000);

                int responseCode = connection.getResponseCode();
                if (responseCode >= 200 && responseCode < 300) {
                    return true;
                } else {
                    logger.warning("Server " + url + " returned HTTP " + responseCode + " (non-200).");
                    attempts++;
                }
            } catch (Exception e) {
                logger.severe("Error checking server " + url + ": " + e.getMessage());
                attempts++;
            }
        }

        return false;
    }

    public static void main(String[] args) {
        if (args.length < 3) {
            System.out.println("Usage: java HealthMonitor <urls> <interval> <maxAttempts> <errorThreshold>");
            return;
        }

        String[] urls = args[0].split(",");
        int interval = Integer.parseInt(args[1]);
        int maxAttempts = Integer.parseInt(args[2]);
        int errorThreshold = Integer.parseInt(args[3]);

        HealthMonitor monitor = new HealthMonitor(urls, interval, maxAttempts, errorThreshold);
        monitor.startMonitoring();
    }
}

