    while let Ok(Some(line)) = lines.next() {
        let url = line?;
        let future = async move {
            let result = fetch_and_parse(url).await?;
            results.insert(url, result.title);
            Ok(())
        };

        spawn(future).await?;
    }

    // Print the hashmap
    for (url, title) in &results {
        println!("{}: {}", url, title);
    }

    Ok(())
}

async fn fetch_and_parse(url: String) -> Result<String, Error> {
    let response = reqwest::get(&url).await?;
    let html = response.text().await?;
    let title = html.parse::<String>().unwrap_or_default();
    Ok(title)
}
