use async_std::prelude::*;
use async_std::io::{self, Write};
use async_std::net::TcpListener;
use serde_json::Value;
use std::io::{BufReader, BufWriter};
use std::sync::{Arc, Mutex};

#[derive(Clone, Debug)]
struct App {
    port: u16,
    business_logic: Box<dyn Fn(&Value) -> Value + 'static>,
    log: Arc<Mutex<String>>,
}

impl App {
    fn new(port: u16, business_logic: Box<dyn Fn(&Value) -> Value + 'static>) -> Self {
        App {
            port,
            business_logic,
            log: Arc::new(Mutex::new(String::new())),
        }
    }

    async fn handle_client(&self, socket: TcpListener::Incoming) {
        let mut reader = BufReader::new(socket.read().await.unwrap());
        let mut writer = BufWriter::new(socket.write().await.unwrap());

        let mut json = String::new();
        reader.read_to_end(&mut json).await.unwrap();

        let value: Value = serde_json::from_str(&json).unwrap();

        let transformed = (self.business_logic)(&value);

        let mut output = String::new();
        serde_json::to_writer(&mut writer, &transformed).unwrap();
        writer.flush().await.unwrap();

        let mut log = self.log.lock().unwrap();
        log.push_str(&format!("Received JSON: {}\nTransformed JSON: {}\n", json, serde_json::to_string(&transformed).unwrap()));
        log.push_str("\n");
        writer.flush().await.unwrap();
    }
}

#[tokio::main]
async fn main() {
    let app = App::new(8080, Box::new(|value: &Value| {
        // Custom business logic
        let mut result = Value::Null;
        if let Some(field) = value.get("data") {
            let mut data = Value::Null;
            if let Some(val) = field.as_str() {
                data = Value::String(val.to_string());
            }
            result = Value::Object(vec![("data".to_string(), data).into()]);
        }
        result
    }));

    let listener = TcpListener::bind(("0.0.0.0", app.port)).await.unwrap();
    println!("Listening on port {}", app.port);

    loop {
        let socket = listener.accept().await.unwrap();
        let log = app.log.clone();
        tokio::spawn(async move {
            app.handle_client(socket).await;
        });
    }
}
