use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::Path;
use std::time::Duration;
use tokio::fs::File as TokioFile;
use tokio::sync::mpsc;
use tokio::time::{sleep, timeout, Duration};
use aws_sdk_s3::Client;
use aws_sdk_s3::operation::put_object::PutObjectRequest;
use aws_sdk_s3::operation::put_object::PutObjectOutput;
use aws_sdk_s3::error::SdkError;
use anyhow::Result;
use anyhow::bail;
use anyhow::Context;

#[tokio::main]
async fn main() -> Result<()> {
    // Initialize S3 client
    let client = Client::new(&config::AWS_CONFIG);

    // Set up logging
    let log = std::io::stdout();
    let mut log = std::io::BufWriter::new(log);

    // Set up event monitoring
    let (sender, receiver) = mpsc::channel(10);

    // Spawn monitoring task
    tokio::spawn(move || {
        let mut watcher = tokio::fs::DirWatcher::new(&"./".to_string())
            .unwrap();
        let mut files = Vec::new();
        let mut last_modified = None;

        watcher
            .watch(|entry| {
                if entry.kind() == tokio::fs::FileKind::File {
                    let path = entry.path().to_string_lossy();
                    let file = File::open(&path).unwrap();
                    let file_name = path.split('/').last().unwrap();
                    let file_size = file.metadata().unwrap().len();

                    // Check if file was created after last modification
                    if let Some(last_modified) = last_modified {
                        if entry.modified().unwrap() > last_modified {
                            // File was created, upload to S3
                            upload_to_s3(&client, &mut log, &file, file_name, file_size, &sender)
                                .await
                                .unwrap();
                            last_modified = Some(entry.modified().unwrap());
                        }
                    }
                }
                Ok(())
            })
            .unwrap();
    });

    // Spawn upload tasks
    for _ in 0..10 {
        let (tx, rx) = mpsc::channel(1);
        let tx = tx.clone();
        let rx = rx.clone();
        tokio::spawn(move || {
            while let Ok(event) = rx.recv() {
                let path = event.path().to_string_lossy();
                let file = File::open(&path).unwrap();
                let file_name = path.split('/').last().unwrap();
                let file_size = file.metadata().unwrap().len();

                // Upload to S3
                upload_to_s3(&client, &mut log, &file, file_name, file_size, &tx)
                    .await
                    .unwrap();
            }
        });
    }

    // Wait for all tasks to complete
    await_forever().await;

    Ok(())
}

async fn upload_to_s3(
    client: &Client,
    log: &mut std::io::BufWriter<std::io::stdout>,
    file: &File,
    file_name: &str,
    file_size: u64,
    tx: &mpsc::Sender<()>,
) -> Result<PutObjectOutput> {
    let file_path = format!("{}.{}", "uploads", file_name);
    let file_path = Path::new(&file_path).to_path_buf();

    let file = TokioFile::open(&file_path).await?;
    let content = std::io::BufReader::new(file).lines().collect::<Vec<_>>();

    let put_request = PutObjectRequest::new()
        .bucket("your-bucket-name")
        .key(file_name)
        .body(content)
        .content_type("application/octet-stream");

    let result = client.put_object(put_request).await?;
    log.write(format!("Uploaded {} to S3: {}", file_name, result).as_bytes()).unwrap();
    tx.send(()).await.unwrap();

    Ok(result)
}

fn await_forever() {
    let mut interval = std::time::Duration::from_secs(1);
    loop {
        std::thread::sleep(interval);
        interval = std::time::Duration::from_secs(1);
    }
}
