public class StockMarketAnalyzer {
    private final ExecutorService executorService = Executors.newFixedThreadPool(10);
    private final Map<String, Stock> stockMap = new ConcurrentHashMap<>();
    private final Map<String, Double> movingAverages = new ConcurrentHashMap<>();
    private final Map<String, Double> fluctuations = new ConcurrentHashMap<>();

    public static void main(String[] args) {
        StockMarketAnalyzer app = new StockMarketAnalyzer();
        app.start();
    }

    private void start() {
        // Simulated streaming API data
        List<StockData> data = Arrays.asList(
            new StockData("AAPL", 150.0, 148.0, 2.0),
            new StockData("GOOGL", 145.0, 143.0, 2.0),
            new StockData("MSFT", 130.0, 128.0, 2.0)
        );

        // Process data in parallel
        executorService.submit(() -> {
            for (StockData stockData : data) {
                processStockData(stockData);
            }
        });
    }

    private void processStockData(StockData stockData) {
        String symbol = stockData.symbol();
        double price = stockData.price();
        double change = stockData.change();

        // Update stock data
        stockMap.put(symbol, new Stock(symbol, price, change));

        // Calculate moving average
        movingAverages.put(symbol, movingAverages.getOrDefault(symbol, 0.0) + price / 2);

        // Calculate fluctuation
        fluctuations.put(symbol, fluctuations.getOrDefault(symbol, 0.0) + Math.abs(change) / 2);

        // Check for alert conditions
        if (fluctuations.get(symbol) > 5.0) {
            System.out.println("Alert: " + symbol + " has fluctuated by more than 5%");
        }
    }

    // Data structure for stock market data
    private record StockData(String symbol, double price, double change) {}

    // Immutable data structure for stock
    private record Stock(String symbol, double price, double change) {}

    // Thread-safe data structures
    private record MovingAverage(String symbol, double value) {}

    private record Fluctuation(String symbol, double value) {}
