use std::thread;
use std::sync::{mpsc, Mutex};
use image::ImageFormat;
use image::GenericImageView;
use std::path::Path;

// Define the target resolution
const TARGET_RESOLUTION: (u32, u32) = (800, 600);

// Define the worker pool
struct Worker {
    handle: thread::Handle,
}

impl Worker {
    fn new(f: Box<dyn FnMut(String) + 'static>) -> Self {
        let (tx, rx) = mpsc::channel();
        let handle = thread::spawn(move || {
            loop {
                match rx.recv() {
                    Ok(path) => f(path),
                    Err(_) => break,
                }
            }
        });
        Worker { handle }
    }
}

// Function to resize image
fn resize_image(path: &str, output_path: &str) -> Result<(), Box<dyn std::error::Error>> {
    let img = image::open(path)?;
    let (width, height) = (img.width(), img.height());
    let (target_width, target_height) = TARGET_RESOLUTION;
    let aspect_ratio = (width as f64 / height as f64) as f64;

    let new_width = if width > target_width {
        target_width as f64 * aspect_ratio
    } else {
        width as f64 * aspect_ratio
    } as u32;

    let new_height = if height > target_height {
        target_height as f64 / aspect_ratio
    } else {
        height as f64 / aspect_ratio
    } as u32;

    let resized = img.resize(new_width, new_height, image::ImageFormat::Jpeg)?;
    resized.save(output_path)?;
    Ok(())
}

// Main function
fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Set up the worker pool
    let (tx, rx) = mpsc::channel();
    let mut workers = Vec::new();

    // Create 10 workers
    for _ in 0..10 {
        let f = Box::new(move |path: String| {
            let output_path = format!("{}-resized.jpg", path);
            resize_image(&path, &output_path)?;
            tx.send(path).unwrap();
        });
        let worker = Worker::new(f);
        workers.push(worker.handle);
    }

    // Start all workers
    for worker in workers {
        worker.join()?;
    }

    Ok(())
}
