use std::io::{BufRead, BufReader, BufWriter, Read, Write};
use std::thread;
use std::time::Duration;
use std::path::Path;

fn main() {
    let mut files = Vec::new();
    let mut reader = BufReader::new(std::io::stdin());
    let mut lines = Vec::new();
    reader.read_to_end(lines).unwrap();

    for line in lines {
        if !line.is_empty() {
            files.push(line);
        }
    }

    let mut handles = Vec::new();
    let mut writers = Vec::new();
    let mut readers = Vec::new();

    for file in files {
        let file_path = Path::new(&file).to_path_buf();
        let writer = BufWriter::new(std::fs::File::create(file_path.with_extension("gz")).unwrap());
        let reader = BufReader::new(std::fs::File::open(file_path).unwrap());
        let handle = thread::spawn(move || {
            let mut reader = reader;
            let mut writer = writer;
            let mut buf = [0; 1024];
            let mut len = 0;
            while let Ok(n) = reader.read(&mut buf) {
                if n == 0 {
                    break;
                }
                let mut new_len = n;
                if new_len > buf.len() {
                    new_len = buf.len();
                }
                writer.write(&buf[..new_len]).unwrap();
                len += new_len;
            }
            println!("Compressed file: {}", file_path);
        });
        handles.push(handle);
        writers.push(writer);
        readers.push(reader);
    }

    for (i, writer) in writers.iter().enumerate() {
        writer.flush().unwrap();
    }

    for handle in handles {
        handle.join().unwrap();
    }
}
