import java.io.*;
import java.net.HttpURLConnection;
import java.net.URL;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.*;

public class DocumentPreviewService {

    private static final String API_ENDPOINT = "https://api.example.com/preview";

    public static void main(String[] args) {
        // Example usage
        String filePath = "example.txt";
        String summary = getSummaryFromFile(filePath);
        System.out.println(summary);
    }

    public static String getSummaryFromFile(String filePath) {
        try {
            File file = new File(filePath);
            if (!file.exists()) {
                throw new IOException("File not found: " + filePath);
            }

            String content = new String(Files.readAllBytes(Paths.get(filePath)));
            String summary = summarizeText(content);
            return summary;
        } catch (IOException e) {
            e.printStackTrace();
            return "Error: " + e.getMessage();
        }
    }

    public static String summarizeText(String text) {
        // Basic summary logic
        int wordCount = text.split("\\s+").length;
        String fileType = "TXT";
        String detectedLanguage = "English";

        return String.format("Summary: %s (Word count: %d, File type: %s, Language: %s)", 
                           text.substring(0, Math.min(200, text.length())), 
                           wordCount, fileType, detectedLanguage);
    }

    public static String getSummaryFromURL(String url) {
        try {
            URL obj = new URL(url);
            HttpURLConnection conn = (HttpURLConnection) obj.openConnection();
            conn.setRequestMethod("GET");

            int responseCode = conn.getResponseCode();
            if (responseCode == HttpURLConnection.HTTP_OK) {
                String summary = readResponse(conn.getInputStream());
                return summary;
            } else {
                return "Error: " + responseCode;
            }
        } catch (IOException e) {
            e.printStackTrace();
            return "Error: " + e.getMessage();
        }
    }

    private static String readResponse(InputStream inputStream) {
        StringBuilder response = new StringBuilder();
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
        return response.toString();
    }
}
